using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class PartsTraining : TrainingContentBase
{
    public PartsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog Overview",
            Slug = "parts-overview",
            Summary = "What parts are, how types and statuses work, Bills of Materials, operations routing, and how parts connect to jobs, inventory, and purchase orders.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","bom","operations","inventory","catalog"]""",
            ContentJson = """{"body":"## Parts Catalog Overview\n\nThe Parts Catalog is the central register for every item your shop manufactures, purchases, or stocks. Each part record captures the full engineering definition — what the part is, what it is made from, how it is built, and where it lives in inventory. Parts connect to nearly every other module in QB Engineer: jobs consume parts, inventory tracks their quantities, purchase orders procure them, sales orders sell them, and operations define how to produce them.\n\n### What Is a Part?\n\nA part is any discrete item that your business tracks. This includes finished goods you manufacture, raw materials you buy, assemblies you build from sub-components, consumables used during production, fasteners, electronics, packaging materials, and tooling. Every part gets a system-generated part number and a human-readable description.\n\n### Part Types\n\nEach part is assigned a type that describes its role in your manufacturing process:\n\n- **Part** — A standard manufactured or purchased component. This is the default type for most items.\n- **Assembly** — A part that is built from other parts. Assemblies have a Bill of Materials (BOM) listing their sub-components. The Assembly type uses a tree icon (account_tree) in the UI to distinguish it visually.\n- **Raw Material** — Base materials purchased in bulk (sheet metal, bar stock, plastic resin, lumber). Typically bought by weight or length and consumed during production.\n- **Consumable** — Items used up during manufacturing but not part of the finished product (cutting fluid, sandpaper, welding gas, gloves).\n- **Tooling** — Molds, dies, jigs, fixtures, and cutting tools. Tooling parts can be linked to a tooling asset in the Assets module for shot count and maintenance tracking.\n- **Fastener** — Screws, bolts, nuts, rivets, clips. Separated from generic parts for BOM clarity and purchasing convenience.\n- **Electronic** — Circuit boards, sensors, wiring harnesses, connectors. Useful when your products include electronic sub-assemblies.\n- **Packaging** — Boxes, foam inserts, labels, shrink wrap. Tracked separately so packaging costs don't get mixed into material costs.\n\n### Part Statuses\n\nEvery part moves through a lifecycle tracked by its status:\n\n- **Draft** — The part record exists but is not ready for use. Engineers can fill in details without the part appearing in production workflows or purchase orders.\n- **Prototype** — The part is in development or testing. It can be used in jobs and inventory but is flagged as not yet finalized.\n- **Active** — The part is fully defined and approved for production, purchasing, and sales. This is the default status for new parts.\n- **Obsolete** — The part is no longer manufactured or purchased. The record is preserved for historical traceability (past jobs, old BOMs, audit trail), but it won't appear in active searches or new orders.\n\nYou can change a part's status at any time from the detail panel using the status buttons at the bottom of the Info tab.\n\n### Revisions\n\nParts support revision tracking. The default revision is 'A'. When a part's design changes, you increment the revision (A → B → C). The revision history is accessible from the detail panel, showing who changed what and when. Revisions let you trace which version of a part was used in a specific job.\n\n### Bill of Materials (BOM)\n\nThe BOM tab on a part's detail panel lists every component needed to build that part. Each BOM entry specifies:\n\n- **Child Part** — The component part (selected via entity picker search)\n- **Quantity** — How many of the child part are needed per parent part\n- **Source Type** — How the component is obtained:\n  - **Make** — Manufactured in-house (triggers a sub-job)\n  - **Buy** — Purchased from a vendor (triggers a purchase order)\n  - **Stock** — Pulled from existing inventory (no procurement needed)\n- **Reference Designator** — An engineering reference (e.g., R1, C4, J2 for electronics) identifying where the component goes in the assembly\n- **Lead Time Days** — How many days it takes to obtain this component. Critical for production planning.\n- **Notes** — Free-form notes about the BOM entry\n\nBOM entries can be viewed in two modes: a flat **table view** with sortable columns and per-column filtering, or a hierarchical **tree view** that shows nested sub-assemblies visually.\n\nThe **Used In** tab shows the reverse relationship — which parent assemblies use this part as a component. Clicking a parent part navigates to its detail panel.\n\n### Operations (Routing)\n\nThe Routing tab (also called Process tab) defines the step-by-step manufacturing process for a part. Each operation represents a production step:\n\n- **Step Number** — The sequence order (1, 2, 3...)\n- **Title** — A short name for the operation (e.g., 'CNC Rough Cut', 'Deburr', 'Anodize')\n- **Instructions** — Detailed work instructions for the operator\n- **Work Center** — Which work center or machine area performs this step\n- **Estimated Minutes** — How long the operation should take\n- **QC Checkpoint** — Whether this step requires a quality inspection before proceeding\n- **QC Criteria** — What to inspect if it is a QC checkpoint\n- **Referenced Operation** — A cross-reference to another operation in the same routing (for dependencies or sub-operations)\n\nOperations can also have **materials** assigned to them — BOM entries that are consumed during that specific operation step. This connects the BOM to the routing, showing exactly which materials are needed at each production step.\n\nOperations support their own file attachments (setup photos, drawings, reference docs) and an activity log with comments for collaboration.\n\nThe routing can be viewed in **list mode** (sequential cards) or **flow mode** (visual flow diagram).\n\n### How Parts Connect to Other Modules\n\n**Jobs:** When a job is created on the Kanban board, it can be linked to a part. The part's BOM drives material requirements, and the part's routing defines the production steps for the job.\n\n**Inventory:** Parts are tracked in inventory storage locations and bins. The part detail panel shows an inventory summary with total quantity on hand and a low-stock warning when quantity drops below the minimum stock threshold.\n\n**Purchase Orders:** When a BOM entry has source type 'Buy', the system knows the component needs to be purchased. Parts with a preferred vendor link streamline PO creation.\n\n**Sales Orders & Quotes:** Parts appear as line items on sales orders and quotes with pricing from the part's price history.\n\n**Assets:** Tooling-type parts can be linked to a tooling asset for shot count tracking and maintenance scheduling.\n\n**Barcode/QR:** Every part can have a barcode label printed for quick identification. Scanning a part's barcode on the parts page searches for and selects that part instantly.\n\n### Inventory Thresholds & Replenishment\n\nThe part form includes inventory management fields:\n\n- **Min Stock Threshold** — The minimum quantity to keep on hand. When inventory drops below this level, a low-stock warning appears.\n- **Reorder Point** — The quantity level at which a reorder should be triggered.\n- **Reorder Quantity** — How many to order when reordering.\n- **Lead Time Days** — Standard lead time for procurement.\n- **Safety Stock Days** — Extra buffer days of stock to maintain.\n\nThese fields feed into inventory planning and the low-stock warning indicator on the part detail panel.\n\n### Pricing\n\nEach part can have a list price with effective dates. The Info tab shows the current price and a history of past prices. You can set a new price at any time — the system automatically marks the previous price as historical. Price history tracks the effective date range and any notes.\n\n### Accounting Integration\n\nWhen an accounting provider (e.g., QuickBooks) is connected, parts can be linked to accounting items. This synchronizes the part record with the accounting system's item catalog. You can link and unlink accounting items from the Info tab.\n\n### View Modes\n\nThe parts list page supports two view modes:\n- **Table View** — A data table with sortable columns (Part #, External Part #, Description, Rev, Type, Status, Material, BOM count). Click column headers to sort. Use the gear icon for column visibility and ordering.\n- **Card Grid View** — A visual card layout showing part thumbnails and key details. Useful for browsing parts visually.\n\nToggle between views using the view mode buttons next to the filters. Your preference is remembered across sessions.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog — Guided Tour",
            Slug = "parts-walkthrough",
            Summary = "A guided tour of the parts list, filters, data table, creating parts, detail dialog tabs (Info, BOM, Used In, Routing, Files, Alternates, Serials, 3D Viewer), and operations.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","bom","operations","walkthrough"]""",
            ContentJson = """{"appRoute":"/parts","startButtonLabel":"Tour Parts Catalog","steps":[{"element":"[data-testid='new-part-btn']","popover":{"title":"Create Part Button","description":"Click here to create a new part. You'll enter the description, type, revision, material, and inventory thresholds. The system auto-generates a unique part number. For assemblies, you'll add BOM entries after creation.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Parts","description":"Search by part number, description, material, or external part number. Results update when you press Enter. Barcode scanners also feed into this field — scan a part's barcode label to find it instantly.","side":"bottom"}},{"element":".filters-bar app-select:first-of-type","popover":{"title":"Status Filter","description":"Filter parts by lifecycle status: Active (approved for use), Draft (work in progress), Prototype (in testing), or Obsolete (no longer used). Select 'All Statuses' to see everything.","side":"bottom"}},{"element":".filters-bar app-select:nth-of-type(2)","popover":{"title":"Type Filter","description":"Filter by part type: Part, Assembly, Raw Material, Consumable, Tooling, Fastener, Electronic, or Packaging. Each type has a specific role in your manufacturing process.","side":"bottom"}},{"element":".view-toggle","popover":{"title":"View Mode Toggle","description":"Switch between Table View (sortable data table with column management) and Card Grid View (visual cards with thumbnails). Your preference is saved and remembered next time you visit.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Parts Data Table","description":"Click any row to open the part detail dialog. Columns include Part #, External Part #, Description, Rev, Type (with icon), Status (color-coded badge), Material, and BOM count. Click column headers to sort. Use the gear icon to show/hide columns and change column order.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog Field Reference",
            Slug = "parts-field-reference",
            Summary = "Complete reference for every field, button, status, type, source type, validation rule, table column, dialog tab, and action in the Parts Catalog module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/parts"]""",
            Tags = """["parts","bom","operations","reference"]""",
            ContentJson = """{"title":"Parts Catalog Field Reference","groups":[{"heading":"Part Form Fields (Create / Edit Dialog)","items":[{"label":"Type (required)","value":"Dropdown: Part, Assembly, RawMaterial, Consumable, Tooling, Fastener, Electronic, Packaging. Determines the icon in the table (Assembly uses account_tree, all others use settings). Default: Part. data-testid: part-type"},{"label":"Description (required)","value":"Text input. A human-readable name for the part (e.g., 'Aluminum Bracket — Left Side', '6061-T6 Bar Stock 1x2'). Must not be empty. data-testid: part-description"},{"label":"Revision","value":"Text input, max 5 characters. Tracks the engineering revision of the part. Default: 'A'. Increment when the design changes (A → B → C). data-testid: part-revision"},{"label":"External Part Number","value":"Text input, optional. The customer's or vendor's part number for cross-referencing. Displayed as a separate column in the parts table. data-testid: part-external-number"},{"label":"Material","value":"Text input, optional. The primary material the part is made from (e.g., '6061-T6 Aluminum', 'ABS Plastic', '304 Stainless Steel'). Shown in the table and detail panel. data-testid: part-material"},{"label":"Mold/Tool Ref","value":"Text input, optional. Reference to the mold or tooling used to produce this part (e.g., 'Mold #42', 'Die Set A-7')."},{"label":"Tooling Asset","value":"Entity picker (searches Assets with type Tooling). Links this part to a tooling asset for shot count tracking and maintenance scheduling. Optional."},{"label":"Part Number","value":"Display only (shown when editing). Auto-generated by the system on creation. Cannot be changed. Format is a sequential identifier."}]},{"heading":"Inventory Replenishment Fields (Part Form — lower section)","items":[{"label":"Min Stock Threshold","value":"Number input, optional. Minimum quantity to keep on hand. When inventory drops below this level, a yellow warning icon and 'Low Stock' label appear in the part detail panel. Must be >= 0."},{"label":"Reorder Point","value":"Number input, optional. The quantity level at which a reorder should be triggered. Used for inventory planning. Must be >= 0."},{"label":"Reorder Quantity","value":"Number input, optional. How many units to order when reordering. Must be >= 0.01."},{"label":"Lead Time Days","value":"Number input, optional. Standard procurement lead time in days. Used in BOM lead time calculations and production planning. Must be >= 0."},{"label":"Safety Stock Days","value":"Number input, optional. Extra buffer days of stock to maintain beyond the calculated reorder point. Must be >= 0."}]},{"heading":"Part Types","items":[{"label":"Part","value":"Standard manufactured or purchased component. Default type. Icon: settings."},{"label":"Assembly","value":"Built from other parts via a Bill of Materials. Icon: account_tree (tree). Add BOM entries after creation to define sub-components."},{"label":"RawMaterial","value":"Base materials purchased in bulk (sheet metal, bar stock, resin). Typically consumed by weight or length. Icon: settings."},{"label":"Consumable","value":"Items used during manufacturing but not part of the finished product (cutting fluid, sandpaper). Icon: settings."},{"label":"Tooling","value":"Molds, dies, jigs, fixtures. Can be linked to a tooling asset for shot count tracking. Icon: settings."},{"label":"Fastener","value":"Screws, bolts, nuts, rivets, clips. Separated for BOM clarity and purchasing. Icon: settings."},{"label":"Electronic","value":"Circuit boards, sensors, wiring, connectors. For products with electronic sub-assemblies. Icon: settings."},{"label":"Packaging","value":"Boxes, foam inserts, labels, shrink wrap. Tracked separately from production materials. Icon: settings."}]},{"heading":"Part Statuses","items":[{"label":"Active (green badge)","value":"Fully defined and approved for production, purchasing, and sales. Default status for new parts."},{"label":"Draft (gray badge)","value":"Part record exists but is not ready for use. Engineers can fill in details without affecting production workflows."},{"label":"Prototype (blue badge)","value":"Part is in development or testing. Can be used in jobs and inventory but flagged as not yet finalized."},{"label":"Obsolete (red badge)","value":"No longer manufactured or purchased. Record preserved for historical traceability. Won't appear in active searches or new orders."}]},{"heading":"BOM Entry Fields (Add BOM Entry Dialog)","items":[{"label":"Child Part (required)","value":"Entity picker searching parts by part number. The component part to add to the BOM. Cannot be the parent part itself."},{"label":"Quantity (required)","value":"Number input. How many of the child part are needed per one unit of the parent part. Must be > 0. Default: 1."},{"label":"Source Type","value":"Dropdown: Make (manufactured in-house), Buy (purchased from vendor), Stock (pulled from inventory). Default: Buy. Displayed as a color-coded chip in the BOM table (Make is highlighted)."},{"label":"Reference Designator","value":"Text input, optional. Engineering reference identifying where the component goes in the assembly (e.g., R1, C4, J2 for electronics)."},{"label":"Lead Time Days","value":"Number input, optional. Days to obtain this specific component. Displayed as 'Xd' in the BOM table."},{"label":"Notes","value":"Textarea (2 rows), optional. Free-form notes about this BOM entry."}]},{"heading":"BOM Source Types","items":[{"label":"Make","value":"Component is manufactured in-house. Triggers sub-job creation during production planning. Highlighted chip in BOM table."},{"label":"Buy","value":"Component is purchased from a vendor. Links to purchase order workflows. Default source type."},{"label":"Stock","value":"Component is pulled from existing inventory. No procurement needed — assumes sufficient stock on hand. Highlighted chip in BOM table."}]},{"heading":"BOM Table Columns","items":[{"label":"# (Sort Order)","value":"Sequence number. Center-aligned, 40px wide."},{"label":"Part (childPartNumber)","value":"Two-line display: part number (bold) and description (muted). Sortable."},{"label":"Qty (quantity)","value":"Quantity needed per parent unit. Center-aligned, 60px wide. Sortable."},{"label":"Source (sourceType)","value":"Make/Buy/Stock chip. Color-coded. 80px wide. Sortable, filterable (enum filter)."},{"label":"Lead Time (leadTimeDays)","value":"Days displayed as 'Xd' or '---' if not set. 90px wide."},{"label":"Ref Des (referenceDesignator)","value":"Engineering reference designator or '---' if empty."},{"label":"Actions","value":"Delete button (trash icon) to remove the BOM entry. Requires confirmation dialog. 40px wide."}]},{"heading":"Used In Table Columns","items":[{"label":"Parent Part (parentPartNumber)","value":"Part number of the parent assembly that uses this part. Sortable. Clickable — navigates to parent part detail."},{"label":"Description (parentDescription)","value":"Description of the parent assembly. Sortable."},{"label":"Qty (quantity)","value":"How many of this part the parent assembly needs. Center-aligned, 60px wide. Sortable."}]},{"heading":"Operation Form Fields (Operation Dialog)","items":[{"label":"Step Number (required)","value":"Number input. Sequence order of this operation in the routing (1, 2, 3...). Must be >= 1. Auto-populated with next available number for new operations."},{"label":"Title (required)","value":"Text input, max 200 characters. Short name for the operation (e.g., 'CNC Rough Cut', 'Deburr', 'Heat Treat', 'Final Assembly')."},{"label":"Instructions","value":"Textarea. Detailed work instructions for the operator performing this step. Supports multi-line text."},{"label":"Work Center","value":"Entity picker (searches work centers). Which machine area or station performs this operation. Optional."},{"label":"Estimated Minutes","value":"Number input, optional. Expected duration of the operation. Must be >= 1 if provided."},{"label":"QC Checkpoint (toggle)","value":"Toggle switch. When ON, this operation requires a quality inspection before the next step can proceed."},{"label":"QC Criteria","value":"Textarea, shown when QC Checkpoint is ON. Describes what to inspect — dimensions, surface finish, tolerances, functional tests."},{"label":"Referenced Operation","value":"Dropdown of other operations in the same routing. For cross-referencing dependencies or sub-operations. Select '-- None --' to clear."}]},{"heading":"Operation Dialog Tabs","items":[{"label":"Details tab","value":"Core operation fields: step number, title, instructions, work center, estimated minutes, QC checkpoint, QC criteria, referenced operation."},{"label":"Materials tab","value":"Assign BOM entries to this operation. Shows which materials are consumed during this specific step. Select from available BOM entries (those not yet assigned to other operations) and specify quantity. Materials can be removed individually."},{"label":"Files tab","value":"Upload and view file attachments specific to this operation — setup photos, drawings, reference documents. Supports images (preview) and videos (playback)."},{"label":"Activity tab","value":"Chronological activity log showing changes and comments. Add comments for collaboration with other team members."}]},{"heading":"Operation Material Fields","items":[{"label":"BOM Entry (select)","value":"Dropdown of available BOM entries not yet assigned to other operations. Shows child part number and description. Required to add a material."},{"label":"Quantity","value":"Number input. How much of the BOM entry material is consumed in this operation. Default: 1."}]},{"heading":"Part Detail Dialog Tabs","items":[{"label":"Info","value":"Core part fields (revision, type, status, material, external part number, mold/tool ref, preferred vendor, tooling asset), barcode info, accounting linkage, inventory summary with low-stock warning, pricing with history and set-price form, and status change buttons."},{"label":"BOM","value":"Bill of Materials with table view (sortable, filterable data table) or tree view (hierarchical visualization). Add/delete BOM entries. Shows component count badge on tab."},{"label":"Used In","value":"Reverse BOM lookup — which parent assemblies use this part as a component. Data table with clickable rows to navigate to parent part. Shows usage count badge on tab."},{"label":"Routing","value":"Manufacturing operations (process steps). List view or flow diagram view. Add/edit/delete operations. Each operation opens a dialog with its own tabs (Details, Materials, Files, Activity)."},{"label":"Files","value":"File attachments for the part — CAD files (.step, .stl, .dxf, .dwg), PDFs, images (.png, .jpg). Drag-and-drop upload zone. Max 50MB per file. Shows file count badge on tab."},{"label":"Alternates","value":"Substitute parts that can be used in place of this part. Manage alternate part relationships."},{"label":"Serials","value":"Serial number tracking. Only visible when the part has serial tracking enabled (isSerialTracked). Shows QR code icon on tab."},{"label":"3D Viewer","value":"Interactive 3D visualization of the part. Only visible when an STL file is attached. Shows view_in_ar icon on tab. Uses Three.js for rendering."}]},{"heading":"Parts List Table Columns","items":[{"label":"Part # (partNumber)","value":"System-generated part number. Sortable. Bold monospace font. 120px wide."},{"label":"Ext Part # (externalPartNumber)","value":"Customer/vendor part number. Sortable. 120px wide."},{"label":"Description","value":"Part description. Sortable. Flexible width."},{"label":"Rev (revision)","value":"Current revision letter. Center-aligned. 60px wide."},{"label":"Type (partType)","value":"Part type with icon. Sortable. Assembly shows tree icon, others show gear icon."},{"label":"Status","value":"Color-coded status badge (Active=green, Draft=gray, Prototype=blue, Obsolete=red). Sortable. Filterable with enum filter."},{"label":"Material","value":"Primary material or '---' if not set."},{"label":"BOM (bomEntryCount)","value":"Number of BOM entries. Center-aligned. 60px wide. Shows count or '---' if zero."}]},{"heading":"Pricing Section (Info Tab)","items":[{"label":"Current Price","value":"Display only. Shows the current unit price with currency formatting and effective date."},{"label":"New Price (input)","value":"Currency input with $ prefix. Required to set a new price. Must be >= 0."},{"label":"Effective From (datepicker)","value":"Date when the new price takes effect. Defaults to today."},{"label":"Notes (input)","value":"Optional notes about the price change (e.g., 'Vendor price increase', 'Volume discount renegotiated')."},{"label":"Set Price (button)","value":"Saves the new price. Previous price automatically becomes historical. Disabled when form is invalid or saving is in progress."},{"label":"Price History","value":"Table showing past prices with columns: Price (currency), Effective (date), Until (date or '---' if still current). Shows last 5 historical entries."}]},{"heading":"Inventory Summary Section (Info Tab)","items":[{"label":"Total Quantity","value":"Display only. Total units across all inventory locations. When below Min Stock Threshold, shows yellow warning icon and 'Low Stock' label."},{"label":"Min Stock","value":"Display only (from part settings). The minimum quantity threshold."},{"label":"Reorder Point","value":"Display only (from part settings). The reorder trigger level."}]},{"heading":"Accounting Linkage Section (Info Tab)","items":[{"label":"Link button","value":"Opens the accounting item selection dialog. Only visible when an accounting provider is connected and the part is not yet linked."},{"label":"Unlink button","value":"Red icon button (link_off). Removes the accounting link. Requires confirmation dialog. Only visible when the part is linked."},{"label":"Linked Item Card","value":"Shows the accounting item name, provider name, and external ID when linked."},{"label":"Not Linked text","value":"Muted text shown when no accounting item is linked."}]},{"heading":"Buttons and Actions","items":[{"label":"Create Part (primary button, page header)","value":"Opens the part creation dialog. data-testid: new-part-btn"},{"label":"Save / Create Part (dialog footer)","value":"Creates or updates the part. Disabled when form is invalid. Shows validation popover on hover when invalid. data-testid: part-save-btn"},{"label":"Cancel (dialog footer)","value":"Closes the dialog without saving."},{"label":"Edit (detail header icon)","value":"Opens the edit dialog pre-filled with the part's current values."},{"label":"Close (detail header icon)","value":"Closes the detail dialog and returns to the parts list."},{"label":"Status buttons (detail Info tab)","value":"Four buttons: Active, Draft, Prototype, Obsolete. Current status is highlighted. Click to change status immediately without opening edit dialog."},{"label":"Add BOM Entry (BOM tab)","value":"Opens the BOM entry creation dialog with entity picker for child part."},{"label":"Delete BOM Entry (BOM table row)","value":"Red trash icon. Removes the BOM entry. Requires confirmation dialog (severity: danger)."},{"label":"Add Operation (Routing tab)","value":"Opens the operation creation dialog. Step number auto-populated with next available."},{"label":"Edit Operation (Routing tab)","value":"Click an operation card to open the edit dialog with all existing data."},{"label":"Delete Operation (Routing tab)","value":"Opens confirmation dialog (severity: danger). Permanently removes the operation from the routing."},{"label":"Add Material (Operation Materials tab)","value":"Assigns a BOM entry to the operation. Select from unassigned BOM entries and specify quantity."},{"label":"Remove Material (Operation Materials tab)","value":"Removes the material assignment from the operation. The BOM entry becomes available for other operations."},{"label":"View Mode Toggle (BOM tab)","value":"Switch between table view (table_rows icon) and tree view (account_tree icon) for BOM display."},{"label":"View Mode Toggle (page level)","value":"Switch between table view and card grid view for the parts list."},{"label":"Row click (parts table)","value":"Opens the part detail dialog showing all tabs and fields."},{"label":"Row click (Used In table)","value":"Navigates to the parent part's detail panel, replacing the current view."}]},{"heading":"Validation Rules","items":[{"label":"Description","value":"Required. Cannot be empty. Validation popover shows 'Description is required' when missing."},{"label":"Type","value":"Required. Must select one of the eight types. Validation popover shows 'Type is required' when missing."},{"label":"Revision","value":"Optional but defaults to 'A'. Max 5 characters."},{"label":"Min Stock Threshold","value":"Optional. Must be >= 0 if provided."},{"label":"Reorder Point","value":"Optional. Must be >= 0 if provided."},{"label":"Reorder Quantity","value":"Optional. Must be >= 0.01 if provided."},{"label":"Lead Time Days","value":"Optional. Must be >= 0 if provided."},{"label":"Safety Stock Days","value":"Optional. Must be >= 0 if provided."},{"label":"BOM Child Part","value":"Required for BOM entry. Validation popover shows 'Child Part is required'."},{"label":"BOM Quantity","value":"Required for BOM entry. Must be > 0. Validation popover shows 'Quantity is required' or 'Quantity must be at least 0.01'."},{"label":"Operation Step Number","value":"Required. Must be >= 1."},{"label":"Operation Title","value":"Required. Max 200 characters."},{"label":"Operation Estimated Minutes","value":"Optional. Must be >= 1 if provided."},{"label":"New Price","value":"Required for setting a price. Must be >= 0."},{"label":"Submit button popover","value":"When any form is invalid, hovering over the Save/Create button shows a validation popover listing which fields need attention."}]},{"heading":"Barcode Scanner Integration","items":[{"label":"Scanner context","value":"Parts page sets scanner context to 'parts'. Scans on this page are routed to the parts search filter."},{"label":"Scan behavior","value":"When a barcode is scanned, the scanned value is placed into the search field and the parts list is reloaded with the scanned value as the search term. This finds the part by its barcode-encoded part number."},{"label":"Supported scanners","value":"USB barcode scanners (keyboard wedge mode) and NFC readers (ACR122U with NTAG215 tags). Scanner must be in keyboard emulation mode."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Parts Catalog Knowledge Check",
            Slug = "parts-quiz",
            Summary = "Test your knowledge of the Parts Catalog: types, statuses, BOM entries, source types, operations, routing, inventory thresholds, and pricing.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["parts","bom","operations","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pt1","text":"You need to create a new part that is built from multiple sub-components. What part type should you select?","options":[{"id":"a","text":"Part"},{"id":"b","text":"Assembly","isCorrect":true},{"id":"c","text":"RawMaterial"},{"id":"d","text":"Consumable"}],"explanation":"Assembly is the correct type for a part that is built from other parts. After creating the Assembly, you'll add BOM entries listing each sub-component and its quantity."},{"id":"pt2","text":"A BOM entry has a source type of 'Make'. What does this mean?","options":[{"id":"a","text":"The component is purchased from an external vendor"},{"id":"b","text":"The component is pulled from existing inventory stock"},{"id":"c","text":"The component is manufactured in-house, which may trigger a sub-job","isCorrect":true},{"id":"d","text":"The component is a raw material that requires no processing"}],"explanation":"Source type 'Make' means the component is manufactured in-house. During production planning, this can trigger the creation of a sub-job to produce the component. 'Buy' is for purchased items and 'Stock' is for pulling from inventory."},{"id":"pt3","text":"You want to track how much cutting fluid is consumed during production but it isn't part of the finished product. What part type is appropriate?","options":[{"id":"a","text":"RawMaterial"},{"id":"b","text":"Part"},{"id":"c","text":"Consumable","isCorrect":true},{"id":"d","text":"Packaging"}],"explanation":"Consumable is the correct type for items used during manufacturing but not part of the finished product. Examples include cutting fluid, sandpaper, welding gas, and gloves."},{"id":"pt4","text":"A part's status is set to 'Obsolete'. What happens to the part record?","options":[{"id":"a","text":"The record is permanently deleted from the database"},{"id":"b","text":"The record is soft-deleted and hidden from all views including search"},{"id":"c","text":"The record is preserved for historical traceability but won't appear in active searches or new orders","isCorrect":true},{"id":"d","text":"The record is moved to an archive table and can only be viewed by admins"}],"explanation":"Obsolete parts are never deleted. The full record (BOM, operations, pricing history, files) is preserved for traceability — past jobs and old BOMs still reference it. The part simply won't appear in active filtered views or be available for new orders."},{"id":"pt5","text":"You need to add a BOM entry for a purchased component that takes 14 days to arrive. Which fields should you fill in?","options":[{"id":"a","text":"Child Part, Quantity, Source Type = Buy, and Lead Time Days = 14","isCorrect":true},{"id":"b","text":"Child Part, Quantity, and Reference Designator only"},{"id":"c","text":"Child Part, Source Type = Stock, and Lead Time Days = 14"},{"id":"d","text":"Child Part, Quantity, Source Type = Make, and Notes = '14 day lead time'"}],"explanation":"For a purchased component, select the child part, set the quantity needed, choose Source Type = Buy (indicating it comes from a vendor), and enter Lead Time Days = 14 to record the procurement timeline. Lead Time Days is a structured field used for planning — don't put it in notes."},{"id":"pt6","text":"What is the purpose of the Reference Designator field on a BOM entry?","options":[{"id":"a","text":"It stores the vendor's catalog number for the component"},{"id":"b","text":"It identifies where the component goes in the assembly, using engineering references like R1, C4, or J2","isCorrect":true},{"id":"c","text":"It links the BOM entry to an operation in the routing"},{"id":"d","text":"It sets the sort order of the BOM entry in the table"}],"explanation":"Reference Designator is an engineering reference that identifies where a component goes in the assembly. It's commonly used in electronics (R1 for resistor 1, C4 for capacitor 4, J2 for connector 2) but can be used for any assembly where component placement matters."},{"id":"pt7","text":"An operation in the routing has the QC Checkpoint toggle turned ON. What does this mean?","options":[{"id":"a","text":"The operation is skipped during production and only performed during quality audits"},{"id":"b","text":"This step requires a quality inspection before the next production step can proceed","isCorrect":true},{"id":"c","text":"The operation automatically generates a QC report when completed"},{"id":"d","text":"Only quality team members can perform this operation"}],"explanation":"When QC Checkpoint is enabled on an operation, it means a quality inspection is required at this step before production can move to the next operation. The QC Criteria field describes what to inspect — dimensions, surface finish, tolerances, functional tests, etc."},{"id":"pt8","text":"You want to see which parent assemblies use a specific part as a component. Where do you look?","options":[{"id":"a","text":"The BOM tab on the part's detail dialog"},{"id":"b","text":"The Used In tab on the part's detail dialog","isCorrect":true},{"id":"c","text":"The Routing tab on the part's detail dialog"},{"id":"d","text":"The Reports module with a BOM explosion report"}],"explanation":"The Used In tab shows the reverse BOM relationship — all parent assemblies that include this part as a component. It displays a data table with parent part number, description, and quantity. Click a row to navigate directly to the parent part's detail."},{"id":"pt9","text":"A part's inventory quantity drops below the Min Stock Threshold. What visual indicator appears?","options":[{"id":"a","text":"The part row turns red in the parts table"},{"id":"b","text":"A yellow warning icon and 'Low Stock' label appear in the part detail panel's inventory summary","isCorrect":true},{"id":"c","text":"An email notification is sent to the purchasing team"},{"id":"d","text":"The part's status automatically changes to Draft"}],"explanation":"When inventory drops below the Min Stock Threshold, the part detail panel's inventory summary section shows a yellow warning icon and 'Low Stock' text next to the total quantity. The part status is not changed automatically — that's a manual action."},{"id":"pt10","text":"What is the difference between the BOM table view and the BOM tree view?","options":[{"id":"a","text":"Table view shows only top-level components; tree view shows all levels"},{"id":"b","text":"Table view is a flat sortable data table with column filtering; tree view shows hierarchical nested sub-assemblies visually","isCorrect":true},{"id":"c","text":"Table view is read-only; tree view allows editing entries inline"},{"id":"d","text":"There is no difference — they show the same information in the same format"}],"explanation":"Table view presents BOM entries as a flat data table with sortable columns, per-column filtering, and action buttons. Tree view shows the same entries in a hierarchical visualization, making it easy to see nested sub-assemblies and their components at a glance."},{"id":"pt11","text":"You want to assign BOM materials to a specific manufacturing step. How do you do this?","options":[{"id":"a","text":"Drag BOM entries from the BOM tab onto the operation in the Routing tab"},{"id":"b","text":"Open the operation dialog, go to the Materials tab, and select from available BOM entries","isCorrect":true},{"id":"c","text":"Edit the BOM entry and set a 'Consumed At Step' field"},{"id":"d","text":"Materials are automatically assigned to operations based on the step number"}],"explanation":"Open the operation dialog (click the operation card in the Routing tab), switch to the Materials tab, and select from BOM entries that haven't been assigned to other operations. Specify the quantity consumed at this step. This connects the BOM to the routing at the operation level."},{"id":"pt12","text":"What file types can be uploaded to a part's Files tab?","options":[{"id":"a","text":"Only PDF and image files"},{"id":"b","text":"PDF, CAD files (STEP, STL, DXF, DWG), and images (PNG, JPG, JPEG), up to 50MB each","isCorrect":true},{"id":"c","text":"Any file type with no size limit"},{"id":"d","text":"Only STL files for 3D viewing"}],"explanation":"The Files tab accepts .pdf, .step, .stl, .dxf, .dwg, .png, .jpg, and .jpeg files with a maximum size of 50MB per file. STL files get special treatment — when one is uploaded, a 3D Viewer tab appears allowing interactive Three.js rendering of the part."},{"id":"pt13","text":"You scan a barcode on the Parts page. What happens?","options":[{"id":"a","text":"A new part is created with the scanned value as the part number"},{"id":"b","text":"The scanned value is placed into the search field and the parts list reloads to find the matching part","isCorrect":true},{"id":"c","text":"The scanned part's detail dialog opens immediately"},{"id":"d","text":"Nothing — barcode scanning is only supported on the Inventory page"}],"explanation":"On the Parts page, the scanner context is set to 'parts'. When a barcode is scanned, the scanned value is automatically placed into the search field and the parts list reloads with that value as the search term. This finds the part by its barcode-encoded part number."},{"id":"pt14","text":"How do you set a new list price for a part?","options":[{"id":"a","text":"Edit the part and change the price field in the edit dialog"},{"id":"b","text":"In the part detail Info tab, fill in the New Price, Effective From date, and optional notes, then click Set Price","isCorrect":true},{"id":"c","text":"Go to Admin → Price Lists and update the price there"},{"id":"d","text":"Prices can only be set through the accounting integration"}],"explanation":"Pricing is managed directly in the part detail panel's Info tab. Enter the new unit price, select the effective date (defaults to today), add optional notes, and click Set Price. The previous price automatically becomes historical and appears in the price history table below."},{"id":"pt15","text":"A part of type Tooling can be linked to which other module?","options":[{"id":"a","text":"The Kanban Board — tooling parts appear as cards on a dedicated Tooling board"},{"id":"b","text":"The Assets module — linked to a tooling asset for shot count tracking and maintenance scheduling","isCorrect":true},{"id":"c","text":"The Vendors module — tooling parts are automatically linked to their manufacturer"},{"id":"d","text":"The Time Tracking module — tooling usage is tracked as time entries"}],"explanation":"Tooling-type parts can be linked to a tooling asset in the Assets module via the Tooling Asset entity picker on the part form. This connects the part to the asset's shot count tracking and maintenance schedule, giving full traceability from the part back to the physical tool that produces it."}]}"""
        });

        Log.Information("Seeded Parts training modules");
    }
}
